&lt;li&gt;&lt;a href=&#34;#target%E9%80%89%E9%A1%B9%E5%8D%A1&#34;&gt;target 选项卡&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#pasitions%E9%80%89%E9%A1%B9%E5%8D%A1&#34;&gt;Pasitions 选项卡&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#%E6%94%BB%E5%87%BB%E6%A8%A1%E5%BC%8F%E6%9C%89%E5%A6%82%E4%B8%8B%E5%9B%9B%E7%A7%8D&#34;&gt;攻击模式有如下四种：&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#payloads%E9%80%89%E9%A1%B9%E5%8D%A1&#34;&gt;Payloads 选项卡&lt;/a&gt;&lt;/li&gt;
&lt;li&gt;&lt;a href=&#34;#options%E9%80%89%E9%A1%B9%E5%8D%A1&#34;&gt;options 选项卡&lt;/a&gt;&lt;/li&gt;
